from collections import defaultdict

_EXP = {1: (0, 0, 0), 2: (1, 0, 0), 3: (0, 1, 0), 4: (2, 0, 0), 5: (0, 0, 1), 6: (1, 1, 0)}


class Solution:
    def countSequences(self, nums, k) -> int:
        kk = k
        target = [0, 0, 0]
        for i, p in enumerate((2, 3, 5)):
            while kk % p == 0:
                kk //= p
                target[i] += 1
        if kk != 1:
            return 0
        target = tuple(target)
        dp = {(0, 0, 0): 1}
        for num in nums:
            ex, ey, ez = _EXP[num]
            ndp = defaultdict(int)
            for (x, y, z), cnt in dp.items():
                ndp[(x + ex, y + ey, z + ez)] += cnt
                ndp[(x - ex, y - ey, z - ez)] += cnt
                ndp[(x, y, z)] += cnt
            dp = ndp
        return dp.get(target, 0)

