var countSequences = function(nums, k) {
    const EXP = { 1: [0, 0, 0], 2: [1, 0, 0], 3: [0, 1, 0], 4: [2, 0, 0], 5: [0, 0, 1], 6: [1, 1, 0] };
    let kk = k;
    const target = [0, 0, 0];
    const primes = [2, 3, 5];
    for (let i = 0; i < 3; i++) {
        while (kk % primes[i] === 0) {
            kk /= primes[i];
            target[i] += 1;
        }
    }
    if (kk !== 1) return 0;
    let dp = new Map();
    dp.set('0,0,0', { vec: [0, 0, 0], cnt: 1 });
    for (const num of nums) {
        const [ex, ey, ez] = EXP[num];
        const ndp = new Map();
        const add = (x, y, z, cnt) => {
            const key = x + ',' + y + ',' + z;
            const existing = ndp.get(key);
            if (existing) existing.cnt += cnt;
            else ndp.set(key, { vec: [x, y, z], cnt });
        };
        for (const { vec, cnt } of dp.values()) {
            const [x, y, z] = vec;
            add(x + ex, y + ey, z + ez, cnt);
            add(x - ex, y - ey, z - ez, cnt);
            add(x, y, z, cnt);
        }
        dp = ndp;
    }
    const targetKey = target.join(',');
    const result = dp.get(targetKey);
    return result ? result.cnt : 0;
};
